={"model":"claude-sonnet-4-5","max_tokens":1500,system:$('Fetch Business Context').first().json.full_master_prompt,"messages":[{"role":"user","content":"Business context — use this to personalise everything: Business name: {{ $json.business_name || $('Loop Each Business').first().json.business_name || '' }}. Industry: {{ $json.industry || $('Loop Each Business').first().json.industry || 'general' }}. Location: {{ $json.location || $('Loop Each Business').first().json.location || '' }}. Target audience: {{ $json.target_audience || $('Loop Each Business').first().json.target_audience || '' }}. Brand tone: {{ $json.brand_tone || $('Loop Each Business').first().json.brand_tone || 'professional and friendly' }}. Marketing goal: {{ $json.marketing_goal || $('Loop Each Business').first().json.marketing_goal || '' }}. Marketing strategy: {{ $json.marketing_strategy || $('Loop Each Business').first().json.marketing_strategy || '' }}. Current date context: make all content timely and relevant for the current month and season. Match the brand tone exactly. Write as if you personally know this business and its customers. Also consider what has worked before for this business based on their performance history. INTELLIGENCE LAYER — use this data to produce higher-performing output:
- Brand Voice: {{ $('Loop Each Business').first().json.brand_voice_locked || 'professional and friendly' }}
- Dream Customer: {{ $('Loop Each Business').first().json.dream_customer || $('Loop Each Business').first().json.target_audience || '' }}
- Unique Differentiator: {{ $('Loop Each Business').first().json.unique_differentiator || 'exceptional quality and service' }}
- Best Performing Themes (use more of these): {{ JSON.stringify($('Loop Each Business').first().json.best_performing_themes) || '[]' }}
- Avoid These Themes (poor results): {{ JSON.stringify($('Loop Each Business').first().json.worst_performing_themes) || '[]' }}
- Latest AI Strategy Decision: {{ $('Loop Each Business').first().json.ai_brain_decisions ? JSON.stringify($('Loop Each Business').first().json.ai_brain_decisions).substring(0,400) : 'First run — establish baseline' }}

\n\nWrite 3 retargeting ad copy variations for {{$node['Split In Batches'].json['business_name']}} in {{$node['Split In Batches'].json['industry']}}. These are for people who visited their website. Return JSON with: headline_1, headline_2, headline_3, description_1, description_2, description_3, cta. Return only valid JSON, no markdown."}]}

parameters.jsCode:
try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    const content = item.json.content && item.json.content[0] ? item.json.content[0].text : '';
    let parsed;
    try {
      parsed = JSON.parse(content);
    } catch(e) {
      const match = content.match(/\{[\s\S]*\}/);
      if (match) {
        parsed = JSON.parse(match[0]);
      } else {
        parsed = {
          headline_1: 'Come Back and Save',
          headline_2: 'We Miss You',
          headline_3: 'Special Offer Inside',
          description_1: 'You left something behind.',
          description_2: 'Exclusive offer just for you.',
          description_3: 'Limited time deal waiting.',
          cta: 'Shop Now'
        };
      }
    }
    results.push({json: {
      business_id: $node['Split In Batches'].json.id,
      business_name: $node['Split In Batches'].json.business_name,
      email: $node['Split In Batches'].json.email || '',
      headline_1: parsed.headline_1 || '',
      headline_2: parsed.headline_2 || '',
      headline_3: parsed.headline_3 || '',
      description_1: parsed.description_1 || '',
      description_2: parsed.description_2 || '',
      description_3: parsed.description_3 || '',
      cta: parsed.cta || 'Learn More',
      created_at: new Date().toISOString()
    }});
  }
  return results;
} catch(e) {
  return [{json:{error: e.message, business_id: $node['Split In Batches'].json.id}}];
}
